"""Abstract base class for iteration plot listeners.

Provides `PlotListener`, a base class for listeners that create plots
of vectors at each iteration of an inverse solver.
"""

import PISM.logging
import PISM.vec

def pauseListener(*args):
    """Pause execution at each iteration, waiting for a key press."""
    PISM.logging.pause()

class PlotListener(object):

    """Base class for listeners that create plots of vectors at each iteration.

    Provides objects for converting :cpp:class:`Array` instances to ``numpy``
    vectors on processor zero, as well as basic ``matplotlib`` figure
    management.

    Parameters
    ----------
    grid : PISM.Grid
        The computational grid.
    """

    def __init__(self, grid):
        self.grid = grid
        self.figs = {}

    def toproczero(self, *args):
        """Convert an :cpp:class:`Array` to a ``numpy`` array on processor zero.

        Parameters
        ----------
        *args : Array or (dict, str)
            Either a single :cpp:class:`Array`, or a dictionary of such arrays
            together with the name of an entry.

        Returns
        -------
        numpy.ndarray or None
            The array data on processor zero, or ``None`` on other processors.
        """
        if len(args) == 2:
            data = args[0]
            name = args[1]
            v = data[name]
        else:
            v = args[0]
        if v is None:
            return None

        return v.to_numpy()

    def figure(self, name='default'):
        """Return a ``matplotlib`` figure number, creating one if needed.

        Parameters
        ----------
        name : str, optional
            Name identifying the figure. If no figure with this name exists
            yet, a new one is created.

        Returns
        -------
        int
            The ``matplotlib`` figure number.
        """
        fig = self.figs.get(name)
        if fig is None:
            import matplotlib.pyplot as pp
            fig = pp.figure()
            self.figs[name] = fig
        return fig.number

    def __call__(self, solver, itr, data):
        """Plot data for the current iteration.

        Parameters
        ----------
        solver : object
            The inverse solver instance.
        itr : int
            The current iteration number.
        data : dict
            Dictionary of data arrays for the current iteration.

        Raises
        ------
        NotImplementedError
            Must be implemented by subclasses.
        """
        raise NotImplementedError()
